import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

function Home() {
    const [osList, setOsList] = useState([]);
    const [filtroNumero, setFiltroNumero] = useState('');
    const [filtroStatus, setFiltroStatus] = useState('todos');
    const [filtroCliente, setFiltroCliente] = useState('');
    const [pagina, setPagina] = useState(1);
    const itensPorPagina = 10;
    const [totalAbertas, setTotalAbertas] = useState(0);
    const [totalConcluidas, setTotalConcluidas] = useState(0);
    const [faturamentoMes, setFaturamentoMes] = useState(0);

    useEffect(() => {
        carregarOS();
    }, []);

    const carregarOS = async () => {
        try {
            const res = await api.get('/os');
            const data = res.data;
            setOsList(data);
            const abertas = data.filter(os => os.status_os !== 'concluido').length;
            const concluidas = data.filter(os => os.status_os === 'concluido').length;
            const mesAtual = new Date().getMonth();
            const anoAtual = new Date().getFullYear();
            const fatMes = data.reduce((acc, os) => {
                if (os.status_os === 'concluido' && os.data_conclusao) {
                    const dataConc = new Date(os.data_conclusao);
                    if (dataConc.getMonth() === mesAtual && dataConc.getFullYear() === anoAtual) {
                        return acc + (parseFloat(os.preco_final) || 0);
                    }
                }
                return acc;
            }, 0);
            setTotalAbertas(abertas);
            setTotalConcluidas(concluidas);
            setFaturamentoMes(fatMes);
        } catch (err) {
            console.error(err);
            setOsList([]);
        }
    };

    const finalizarOS = async (id) => {
        if (window.confirm('Finalizar esta OS? O tempo será encerrado e status alterado para CONCLUÍDO.')) {
            try {
                await api.put(`/os/${id}`, { status_os: 'concluido' });
                carregarOS();
            } catch (err) {
                alert('Erro ao finalizar OS');
            }
        }
    };

    const osFiltradas = osList.filter(os => {
        if (filtroNumero && !os.numero_os?.toLowerCase().includes(filtroNumero.toLowerCase())) return false;
        if (filtroStatus === 'abertos' && os.status_os === 'concluido') return false;
        if (filtroStatus === 'concluidos' && os.status_os !== 'concluido') return false;
        if (filtroCliente && !os.cliente_nome?.toLowerCase().includes(filtroCliente.toLowerCase())) return false;
        return true;
    });

    const totalPaginas = Math.ceil(osFiltradas.length / itensPorPagina);
    const osExibidas = osFiltradas.slice((pagina-1)*itensPorPagina, pagina*itensPorPagina);

    return (
        <div>
            <div style={{ textAlign: 'center', marginBottom: '30px' }}>
                <h1 style={{
                    fontSize: '2rem', fontWeight: 'bold', textTransform: 'uppercase',
                    background: 'linear-gradient(135deg, #1e3c72, #2a5298)',
                    color: 'white', padding: '15px 25px', borderRadius: '50px',
                    display: 'inline-block', boxShadow: '0 8px 20px rgba(0,0,0,0.2)'
                }}>📊 DASHBOARD - MWR SISTEMA</h1>
            </div>

            <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', marginBottom: '40px', flexWrap: 'wrap' }}>
                <div style={{ background: '#fff', padding: '15px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)', width: '200px', textAlign: 'center', borderTop: '5px solid #ffc107' }}>
                    <div style={{ fontSize: '2.5rem' }}>🟠</div>
                    <div><strong>OS Abertas</strong></div>
                    <div style={{ fontSize: '28px', fontWeight: 'bold' }}>{totalAbertas}</div>
                </div>
                <div style={{ background: '#fff', padding: '15px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)', width: '200px', textAlign: 'center', borderTop: '5px solid #28a745' }}>
                    <div style={{ fontSize: '2.5rem' }}>✅</div>
                    <div><strong>OS Concluídas</strong></div>
                    <div style={{ fontSize: '28px', fontWeight: 'bold' }}>{totalConcluidas}</div>
                </div>
                <div style={{ background: '#fff', padding: '15px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)', width: '200px', textAlign: 'center', borderTop: '5px solid #007bff' }}>
                    <div style={{ fontSize: '2.5rem' }}>💰</div>
                    <div><strong>Faturamento (mês)</strong></div>
                    <div style={{ fontSize: '28px', fontWeight: 'bold' }}>R$ {faturamentoMes.toFixed(2)}</div>
                </div>
            </div>

            <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap', marginBottom: '25px', background: '#fff', padding: '15px', borderRadius: '16px', boxShadow: '0 1px 4px rgba(0,0,0,0.05)' }}>
                <input type="text" placeholder="🔍 Nº da OS" value={filtroNumero} onChange={e => setFiltroNumero(e.target.value)} style={{ flex: 1, padding: '10px', borderRadius: '30px', border: '1px solid #ddd' }} />
                <select value={filtroStatus} onChange={e => setFiltroStatus(e.target.value)} style={{ padding: '10px', borderRadius: '30px', border: '1px solid #ddd' }}>
                    <option value="todos">Todos os status</option>
                    <option value="abertos">Somente abertos</option>
                    <option value="concluidos">Somente concluídos</option>
                </select>
                <input type="text" placeholder="👤 Nome do cliente" value={filtroCliente} onChange={e => setFiltroCliente(e.target.value)} style={{ flex: 1, padding: '10px', borderRadius: '30px', border: '1px solid #ddd' }} />
            </div>

            <div style={{ overflowX: 'auto', borderRadius: '16px', boxShadow: '0 2px 10px rgba(0,0,0,0.05)' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
                    <thead style={{ background: '#2c3e50', color: 'white' }}>
                        <tr><th style={{ padding: '14px' }}>Nº OS</th><th>Cliente</th><th>Equipamento</th><th>Status</th><th>Valor (R$)</th><th>Ações</th></tr>
                    </thead>
                    <tbody>
                        {osExibidas.length === 0 ? (
                            <tr><td colSpan="6" style={{ textAlign: 'center', padding: '40px' }}>Nenhuma OS encontrada</td></tr>
                        ) : (
                            osExibidas.map(os => (
                                <tr key={os.id} style={{ borderBottom: '1px solid #eee', backgroundColor: os.status_os === 'concluido' ? '#f8fff8' : '#fff' }}>
                                    <td style={{ padding: '12px' }}>{os.numero_os}</td>
                                    <td>{os.cliente_nome}</td>
                                    <td>{os.equipamento} {os.modelo}</td>
                                    <td><span style={{ backgroundColor: os.status_os === 'concluido' ? '#28a745' : '#ffc107', color: '#000', padding: '5px 12px', borderRadius: '30px', fontSize: '12px', fontWeight: 'bold' }}>{os.status_os === 'concluido' ? 'CONCLUÍDO' : 'ABERTO'}</span></td>
                                    <td>R$ {parseFloat(os.preco_final || 0).toFixed(2)}</td>
                                    <td>
                                        <Link to={`/os/${os.id}`}><button style={{ marginRight: '6px', padding: '6px 12px', background: '#17a2b8', color: 'white', border: 'none', borderRadius: '20px', cursor: 'pointer' }}>Ver</button></Link>
                                        <Link to={`/os/editar/${os.id}`}><button style={{ marginRight: '6px', padding: '6px 12px', background: '#ffc107', color: 'black', border: 'none', borderRadius: '20px', cursor: 'pointer' }}>Editar</button></Link>
                                        {os.status_os !== 'concluido' && <button onClick={() => finalizarOS(os.id)} style={{ padding: '6px 12px', background: '#dc3545', color: 'white', border: 'none', borderRadius: '20px', cursor: 'pointer' }}>Finalizar</button>}
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPaginas > 1 && (
                <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginTop: '30px' }}>
                    <button onClick={() => setPagina(p => Math.max(1, p-1))} disabled={pagina === 1} style={{ padding: '8px 20px', background: '#007bff', color: 'white', border: 'none', borderRadius: '30px', cursor: 'pointer' }}>Anterior</button>
                    <span>Página {pagina} de {totalPaginas}</span>
                    <button onClick={() => setPagina(p => Math.min(totalPaginas, p+1))} disabled={pagina === totalPaginas} style={{ padding: '8px 20px', background: '#007bff', color: 'white', border: 'none', borderRadius: '30px', cursor: 'pointer' }}>Próxima</button>
                </div>
            )}
        </div>
    );
}

export default Home;
